// @venom: browser
import React from "../jsx-runtime"; import type { TrendPoint } from "../data/types";
interface TrendChartProps { points:TrendPoint[]; }
export default function TrendChart({points}:TrendChartProps){ const max=Math.max(...points.map(point=>point.risk),1); return <article className="panel trend-panel"><div className="panel-heading"><div><p className="eyebrow">Protected analytics</p><h2>Risk movement</h2></div><div className="legend"><span><i className="legend-risk"></i>Risk index</span><span><i className="legend-base"></i>Baseline</span></div></div><div className="chart-area"><div className="chart-grid"><span>100</span><span>75</span><span>50</span><span>25</span><span>0</span></div><div className="bar-chart">{points.map(point=><div className="bar-column"><div className="bar-value">{point.risk}</div><div className="bar-track"><div className="bar-fill" data-height={Math.round(point.risk/max*100)} style={`height:${Math.round(point.risk/max*100)}%`}></div></div><small>{point.label}</small></div>)}</div></div></article>; }
